import { motion } from 'framer-motion';

function DraggableBox() {
  return (
    <motion.div
      drag
      dragConstraints={{ left: 0, right: 300, top: 0, bottom: 300 }}
      whileHover={{ scale: 1.1 }}
      whileTap={{ scale: 0.9 }}
      style={{
        width: 100,
        height: 100,
        background: 'linear-gradient(135deg, #8B5CF6, #06B6D4)',
        borderRadius: 16,
        cursor: 'grab'
      }}
    />
  );
}

